import re

def generate_ass(txt_path, ass_path, translations):
    with open(txt_path, 'r', encoding='utf-8') as f:
        lines = f.readlines()

    ass_header = """[Script Info]
; Script generated by Antigravity
Title: Claude Code Lesson 4 Bilingual Subtitles
ScriptType: v4.00+
WrapStyle: 0
ScaledBorderAndShadow: yes
YCbCr Matrix: TV.709
PlayResX: 1920
PlayResY: 1080

[V4+ Styles]
Format: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, Underline, StrikeOut, ScaleX, ScaleY, Spacing, Angle, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding
Style: Default,Arial,20,&H00FFFFFF,&H000000FF,&H00000000,&H00000000,0,0,0,0,100,100,0,0,1,2,2,2,10,10,50,1

[Events]
Format: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text
"""

    pattern = re.compile(r'\[(\d+):(\d+)\] (.*)')
    dialogues = []
    
    for i in range(len(lines)):
        match = pattern.match(lines[i].strip())
        if match:
            m = int(match.group(1))
            s = int(match.group(2))
            text_en = match.group(3).strip()
            
            # Format time HH:MM:SS.CC
            h = m // 60
            rm = m % 60
            start_time = f"{h}:{rm:02}:{s:02}.00"
            
            # Find next timestamp for end time
            end_time = None
            if i + 1 < len(lines):
                next_match = pattern.match(lines[i+1].strip())
                if next_match:
                    nm = int(next_match.group(1))
                    ns = int(next_match.group(2))
                    nh = nm // 60
                    nrm = nm % 60
                    end_time = f"{nh}:{nrm:02}:{ns:02}.00"
            
            if not end_time:
                end_time = f"{h}:{rm:02}:{(s+3):02}.00" # Default 3s for last line

            text_zh = translations.get(text_en, text_en)
            dialogues.append(f"Dialogue: 0,{start_time},{end_time},Default,,0,0,0,,{{\\fs80}}{text_zh}\\N{{\\fs50}}{text_en}")

    with open(ass_path, 'w', encoding='utf-8') as f:
        f.write(ass_header)
        for d in dialogues:
            f.write(d + "\n")

